SELECT t.topic_id AS topicId, t.topic_name AS topicName, t.academic_year AS academicYear, t.max_students AS maxStudents, t.current_count AS currentCount, t.status, t.description, t.campus_id AS campusId, t.campus_name AS campusName, t.create_time AS createTime, t.update_time AS updateTime FROM project_topic t WHERE t.is_deleted = 0
AND t.campus_id = #{campusId}
AND t.campus_name LIKE CONCAT('%', #{campusName}, '%')
AND t.academic_year = #{academicYear}
AND t.status = #{status}
AND t.topic_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY t.topic_id DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM project_topic t
WHERE t.is_deleted = 0

    AND t.campus_id = #{campusId}


    AND t.campus_name LIKE CONCAT('%', #{campusName}, '%')


